ruleSearch.bookList:
@js:JSON.parse(result).data.data.map(o =>{
     if(o.id.includes('jq'))return{}
     var J = JSON.parse(java.ajax("https://rs.resouxs.com/book/view?bookId="+o.id)).data.data;
     return{
        name:o.novelName,
        author:o.authorName,
        tags:o.categoryName,
        num:J.totalWord+'字',
        latest:J.updateChapterName+String(java.timeFormat(J.updateTime)).replace(/(\d+\/\d+\/\d+).*/,'（$1）'),
        intro:o.content,
        cover:o.coverUrl,
        catalogUrl:'https://rs.resouxs.com/book/catalogList?bookId='+o.id
     }
}).filter(v =>v.name);
